import { describe, it, expect, vi, beforeEach, afterEach } from "vitest";
import * as fs from "fs";
import * as path from "path";
import * as os from "os";
import {
  detectMcpClients,
  addSequantToMcpConfig,
  getSequantMcpConfig,
