      const output = consoleLogSpy.mock.calls.map((c) => c[0]).join("\n");
      expect(output).toContain("Using stack: generic (default)");
      expect(mockSaveConfig).toHaveBeenCalledWith(
        expect.objectContaining({
          stack: "generic",
